code = """import json

# Get stockinfo data
stockinfo_result = locals()['var_functions.query_db:0']

# Build company info mapping
company_info = {}
for item in stockinfo_result:
    symbol = item['Symbol']
    desc = item['Company Description']
    company_name = desc.split(' specializes')[0].split(' is ')[0].split(' harnesses')[0].split(' provides')[0].strip()
    company_name = company_name.rstrip(',')
    company_info[symbol] = {
        'name': company_name,
        'status': item['Financial Status']
    }

# Trading results from query_db calls
trading_data = {
    'APEX': 23781.422924901184,
    'BKYI': 10988.142292490118,
    'CBAT': 86223.32015810277,
    'CCCL': 4366.798418972332,
    'CORV': 145247.8260869565,
    'CPAH': 375.49407114624506,
    'DZSI': 15578.656126482214,
    'FTR': 254397.62845849802,
    'FTFT': 9.845238095238095,
    'IDEX': 10.276679841897232,
    'OPTT': 254.1501976284585,
    'PEIX': 10706.719367588932,
    'SES': 2390.513833992095,
    'SYPR': 36836.36363636364
}

# Create results
results = []
for symbol, avg_vol in trading_data.items():
    info = company_info[symbol]
    status_code = info['status']
    if status_code == 'D':
        status = 'Deficient'
    elif status_code == 'E':
        status = 'Delinquent'
    elif status_code == 'H':
        status = 'Deficient & Delinquent'
    else:
        status = status_code
    
    results.append({
        'company': info['name'],
        'ticker': symbol,
        'status': status,
        'volume': round(avg_vol)
    })

# Sort by company name
results.sort(key=lambda x: x['company'])

# Create output format
output = "NASDAQ-Listed Companies Financially Troubled with 2008 Trading Volum" + "|"
for r in results:
    line = f"{r['company']} ({r['ticker']}) - Status: {r['status']} - Avg Volume 2008: {r['volume']:,}"
    output += line + "|"

print('__RESULT__:')
print(json.dumps(output))"""

